// ─── OGL WebGL Circular Gallery ───────────────────────────────────────────────
function lerp(p1, p2, t) { return p1 + (p2 - p1) * t; }
function debounce(func, wait) {
  let timeout;
  return function (...args) { window.clearTimeout(timeout); timeout = window.setTimeout(() => func.apply(this, args), wait); };
}
function getFontSize(font) { const m = font.match(/(\d+)px/); return m ? parseInt(m[1]) : 30; }
function createTextTexture(gl, text, font = "bold 24px sans-serif", color = "#10b981") {
  const canvas = document.createElement("canvas");
  const ctx = canvas.getContext("2d");
  ctx.font = font;
  const metrics = ctx.measureText(text);
  canvas.width = Math.ceil(metrics.width) + 40;
  canvas.height = Math.ceil(getFontSize(font) * 1.5) + 20;
  ctx.font = font;
  ctx.fillStyle = color;
  ctx.textBaseline = "middle";
  ctx.textAlign = "center";
  ctx.fillText(text, canvas.width / 2, canvas.height / 2);
  const texture = new Texture(gl, { generateMipmaps: false });
  texture.image = canvas;
  return { texture, width: canvas.width, height: canvas.height };
}

class Title {
  constructor({ gl, plane, renderer, text, textColor = "#10b981", font = "bold 24px sans-serif" }) {
    this.gl = gl; this.plane = plane; this.renderer = renderer;
    this.text = text; this.textColor = textColor; this.font = font;
    this.createMesh();
  }
  createMesh() {
    const { texture, width, height } = createTextTexture(this.gl, this.text, this.font, this.textColor);
    const geometry = new Plane(this.gl);
    const program = new Program(this.gl, {
      vertex: `attribute vec3 position;attribute vec2 uv;uniform mat4 modelViewMatrix;uniform mat4 projectionMatrix;varying vec2 vUv;void main(){vUv=uv;gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0);}`,
      fragment: `precision highp float;uniform sampler2D tMap;varying vec2 vUv;void main(){vec4 c=texture2D(tMap,vUv);if(c.a<0.1)discard;gl_FragColor=c;}`,
      uniforms: { tMap: { value: texture } }, transparent: true
    });
    this.mesh = new Mesh(this.gl, { geometry, program });
    const aspect = width / height;
    const th = this.plane.scale.y * 0.12;
    this.mesh.scale.set(th * aspect, th, 1);
    this.mesh.position.y = -this.plane.scale.y * 0.5 - th * 0.6 - 0.05;
    this.mesh.setParent(this.plane);
  }
}

class Media {
  constructor({ geometry, gl, image, index, length, renderer, scene, screen, text, viewport, bend, textColor, borderRadius = 0.1, font }) {
    Object.assign(this, { geometry, gl, image, index, length, renderer, scene, screen, text, viewport, bend, textColor, borderRadius, font });
    this.extra = 0; this.speed = 0;
    this.createShader(); this.createMesh(); this.createTitle(); this.onResize();
  }
  createShader() {
    const texture = new Texture(this.gl, { generateMipmaps: true });
    this.program = new Program(this.gl, {
      depthTest: false, depthWrite: false,
      vertex: `precision highp float;attribute vec3 position;attribute vec2 uv;uniform mat4 modelViewMatrix;uniform mat4 projectionMatrix;uniform float uTime;uniform float uSpeed;varying vec2 vUv;void main(){vUv=uv;vec3 p=position;p.z=(sin(p.x*4.0+uTime)*1.5+cos(p.y*2.0+uTime)*1.5)*(0.1+uSpeed*0.5);gl_Position=projectionMatrix*modelViewMatrix*vec4(p,1.0);}`,
      fragment: `precision highp float;uniform vec2 uImageSizes;uniform vec2 uPlaneSizes;uniform sampler2D tMap;uniform float uBorderRadius;varying vec2 vUv;float rBox(vec2 p,vec2 b,float r){vec2 d=abs(p)-b;return length(max(d,vec2(0.0)))+min(max(d.x,d.y),0.0)-r;}void main(){vec2 ratio=vec2(min((uPlaneSizes.x/uPlaneSizes.y)/(uImageSizes.x/uImageSizes.y),1.0),min((uPlaneSizes.y/uPlaneSizes.x)/(uImageSizes.y/uImageSizes.x),1.0));vec2 uv=vec2(vUv.x*ratio.x+(1.0-ratio.x)*0.5,vUv.y*ratio.y+(1.0-ratio.y)*0.5);vec4 color=texture2D(tMap,uv);float d=rBox(vUv-0.5,vec2(0.5-uBorderRadius),uBorderRadius);float alpha=1.0-smoothstep(-0.002,0.002,d);gl_FragColor=vec4(color.rgb,alpha);}`,
      uniforms: { tMap: { value: texture }, uPlaneSizes: { value: [0,0] }, uImageSizes: { value: [0,0] }, uSpeed: { value: 0 }, uTime: { value: 100*Math.random() }, uBorderRadius: { value: this.borderRadius } },
      transparent: true
    });
    const img = new Image(); img.crossOrigin = "anonymous"; img.src = this.image;
    img.onload = () => { texture.image = img; this.program.uniforms.uImageSizes.value = [img.naturalWidth, img.naturalHeight]; };
  }
  createMesh() { this.plane = new Mesh(this.gl, { geometry: this.geometry, program: this.program }); this.plane.setParent(this.scene); }
  createTitle() { this.title = new Title({ gl: this.gl, plane: this.plane, renderer: this.renderer, text: this.text, textColor: this.textColor, font: this.font }); }
  update(scroll, direction) {
    this.plane.position.x = this.x - scroll.current - this.extra;
    const x = this.plane.position.x; const H = this.viewport.width / 2;
    if (this.bend === 0) { this.plane.position.y = 0; this.plane.rotation.z = 0; }
    else {
      const B = Math.abs(this.bend);
      const R = (H*H + B*B) / (2*B);
      const ex = Math.min(Math.abs(x), H);
      const arc = R - Math.sqrt(Math.max(0, R*R - ex*ex));
      this.plane.position.y = this.bend > 0 ? -arc : arc;
      this.plane.rotation.z = (this.bend > 0 ? -1 : 1) * Math.sign(x) * Math.asin(Math.min(ex/R, 1));
    }
    this.speed = scroll.current - scroll.last;
    this.program.uniforms.uTime.value += 0.04;
    this.program.uniforms.uSpeed.value = this.speed;
    const po = this.plane.scale.x/2; const vo = this.viewport.width/2;
    const isBefore = this.plane.position.x + po < -vo;
    const isAfter = this.plane.position.x - po > vo;
    if (direction === "right" && isBefore) this.extra -= this.widthTotal;
    if (direction === "left" && isAfter) this.extra += this.widthTotal;
  }
  onResize({ screen, viewport } = {}) {
    if (screen) this.screen = screen;
    if (viewport) this.viewport = viewport;
    this.scale = this.screen.height / 1500;
    this.plane.scale.y = (this.viewport.height * (900*this.scale)) / this.screen.height;
    this.plane.scale.x = (this.viewport.width * (700*this.scale)) / this.screen.width;
    this.program.uniforms.uPlaneSizes.value = [this.plane.scale.x, this.plane.scale.y];
    this.padding = 2;
    this.width = this.plane.scale.x + this.padding;
    this.widthTotal = this.width * this.length;
    this.x = this.width * this.index;
  }
}

class AppCore {
  constructor(container, { items, bend=3, textColor="#10b981", borderRadius=0.1, font="bold 22px sans-serif", scrollSpeed=2, scrollEase=0.05 }) {
    this.container = container; this.scrollSpeed = scrollSpeed;
    this.scroll = { ease: scrollEase, current: 0, target: 0, last: 0 };
    this.onCheckDebounce = debounce(this.onCheck.bind(this), 200);
    this.isDown = false; this.start = 0; this.medias = [];
    this.createRenderer(); this.createCamera(); this.createScene();
    this.onResize(); this.createGeometry();
    this.createMedias(items, bend, textColor, borderRadius, font);
    this.update(); this.addEventListeners();
  }
  createRenderer() {
    this.renderer = new Renderer({ alpha: true, antialias: true, dpr: Math.min(window.devicePixelRatio||1, 2) });
    this.gl = this.renderer.gl; this.gl.clearColor(0,0,0,0);
    this.container.appendChild(this.renderer.gl.canvas);
  }
  createCamera() { this.camera = new Camera(this.gl); this.camera.fov = 45; this.camera.position.z = 20; }
  createScene() { this.scene = new Transform(); }
  createGeometry() { this.planeGeometry = new Plane(this.gl, { heightSegments: 50, widthSegments: 100 }); }
  createMedias(items, bend, textColor, borderRadius, font) {
    const doubled = (items||[]).concat(items||[]);
    this.medias = doubled.map((d,i) => new Media({ geometry: this.planeGeometry, gl: this.gl, image: d.image, index: i, length: doubled.length, renderer: this.renderer, scene: this.scene, screen: this.screen, text: d.text, viewport: this.viewport, bend, textColor, borderRadius, font }));
  }
  onTouchDown(e) { this.isDown = true; this.scroll.position = this.scroll.current; this.start = "touches" in e ? e.touches[0].clientX : e.clientX; }
  onTouchMove(e) { if (!this.isDown) return; const x = "touches" in e ? e.touches[0].clientX : e.clientX; this.scroll.target = (this.scroll.position??0) + (this.start-x)*this.scrollSpeed*0.025; }
  onTouchUp() { this.isDown = false; this.onCheck(); }
  onWheel(e) { const d = e.deltaY||e.wheelDelta||e.detail; this.scroll.target += (d>0?this.scrollSpeed:-this.scrollSpeed)*0.2; this.onCheckDebounce(); }
  onCheck() { if (!this.medias[0]) return; const w=this.medias[0].width; const i=Math.round(Math.abs(this.scroll.target)/w); this.scroll.target = this.scroll.target<0 ? -(w*i) : w*i; }
  onResize() {
    this.screen = { width: this.container.clientWidth, height: this.container.clientHeight };
    this.renderer.setSize(this.screen.width, this.screen.height);
    this.camera.perspective({ aspect: this.screen.width/this.screen.height });
    const fov = (this.camera.fov*Math.PI)/180;
    const height = 2*Math.tan(fov/2)*this.camera.position.z;
    this.viewport = { width: height*this.camera.aspect, height };
    if (this.medias) this.medias.forEach(m=>m.onResize({ screen: this.screen, viewport: this.viewport }));
  }
  update() {
    this.scroll.current = lerp(this.scroll.current, this.scroll.target, this.scroll.ease);
    const dir = this.scroll.current > this.scroll.last ? "right" : "left";
    if (this.medias) this.medias.forEach(m=>m.update(this.scroll, dir));
    this.renderer.render({ scene: this.scene, camera: this.camera });
    this.scroll.last = this.scroll.current;
    this.raf = window.requestAnimationFrame(this.update.bind(this));
  }
  addEventListeners() {
    this._r=this.onResize.bind(this); this._w=this.onWheel.bind(this);
    this._d=this.onTouchDown.bind(this); this._m=this.onTouchMove.bind(this); this._u=this.onTouchUp.bind(this);
    window.addEventListener("resize",this._r); window.addEventListener("wheel",this._w,{passive:true});
    window.addEventListener("mousedown",this._d); window.addEventListener("mousemove",this._m); window.addEventListener("mouseup",this._u);
    window.addEventListener("touchstart",this._d,{passive:true}); window.addEventListener("touchmove",this._m,{passive:true}); window.addEventListener("touchend",this._u);
  }
  destroy() {
    window.cancelAnimationFrame(this.raf);
    ["resize","wheel","mousedown","mousemove","mouseup","touchstart","touchmove","touchend"].forEach((e,i) => {
      const handlers = [this._r,this._w,this._d,this._m,this._u,this._d,this._m,this._u];
      window.removeEventListener(e, handlers[i]);
    });
    if (this.renderer?.gl?.canvas?.parentNode) this.renderer.gl.canvas.parentNode.removeChild(this.renderer.gl.canvas);
  }
}

function CircularGallery({ items, bend=3, textColor="#10b981", borderRadius=0.1, font="bold 22px sans-serif", scrollSpeed=2, scrollEase=0.05 }) {
  const ref = useRef(null);
  useEffect(() => {
    if (!ref.current) return;
    const app = new AppCore(ref.current, { items, bend, textColor, borderRadius, font, scrollSpeed, scrollEase });
    return () => app.destroy();
  }, []);
  return <div ref={ref} style={{ width:"100%", height:"100%", overflow:"hidden", cursor:"grab" }} />;
}

// ─── Hooks ────────────────────────────────────────────────────────────────────
function useCountUp(target, duration=2000, start=false) {
  const [count, setCount] = useState(0);
  useEffect(() => {
    if (!start) return;
    let startTime = null;
    const step = (ts) => {
      if (!startTime) startTime = ts;
      const progress = Math.min((ts - startTime) / duration, 1);
      const ease = 1 - Math.pow(1 - progress, 3);
      setCount(Math.floor(ease * target));
      if (progress < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [start]);
  return count;
}

function useInView(threshold=0.15) {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setInView(true); obs.disconnect(); } }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return [ref, inView];
}

