// ─── Spotlight Card ───────────────────────────────────────────────────────────
function SpotlightCard({ children, style={} }) {
  const ref = useRef(null);
  const onMouseMove = (e) => {
    const rect = ref.current?.getBoundingClientRect();
    if (!rect) return;
    ref.current.style.setProperty("--mx", `${e.clientX - rect.left}px`);
    ref.current.style.setProperty("--my", `${e.clientY - rect.top}px`);
  };
  return <div ref={ref} onMouseMove={onMouseMove} className="sc" style={style}>{children}</div>;
}

function StatCard({ value, suffix, label, start }) {
  const count = useCountUp(value, 2200, start);
  return (
    <div style={{ textAlign:"center" }}>
      <div style={{ fontFamily:"'Newsreader',serif", fontSize:"clamp(2.2rem,4vw,3.5rem)", fontWeight:700, color:"#10b981", lineHeight:1, letterSpacing:"-0.02em" }}>
        {count.toLocaleString()}{suffix}
      </div>
      <div style={{ fontFamily:"'Space Grotesk',monospace", fontSize:"0.6rem", letterSpacing:"0.2em", color:"rgba(235,235,235,0.4)", textTransform:"uppercase", marginTop:"0.5rem" }}>
        {label}
      </div>
    </div>
  );
}

