// ─── Custom Cursor Component ──────────────────────────────────────────────────
function CustomCursor() {
  const dotRef = useRef(null);
  const ringRef = useRef(null);
  const pos = useRef({ x: 0, y: 0 });
  const ring = useRef({ x: 0, y: 0 });
  const raf = useRef(null);
  const [visible, setVisible] = useState(false);
  const [clicked, setClicked] = useState(false);
  const [onLink, setOnLink] = useState(false);

  useEffect(() => {
    const onMove = (e) => {
      pos.current = { x: e.clientX, y: e.clientY };
      if (dotRef.current) {
        dotRef.current.style.left = e.clientX + "px";
        dotRef.current.style.top = e.clientY + "px";
      }
      if (!visible) setVisible(true);
      const el = document.elementFromPoint(e.clientX, e.clientY);
      const isLink = el && (el.closest("a") || el.closest("button") || el.tagName === "A" || el.tagName === "BUTTON");
      setOnLink(!!isLink);
    };
    const onDown = () => setClicked(true);
    const onUp = () => setClicked(false);
    const onLeave = () => setVisible(false);
    const onEnter = () => setVisible(true);

    const animate = () => {
      ring.current.x = lerp(ring.current.x, pos.current.x, 0.12);
      ring.current.y = lerp(ring.current.y, pos.current.y, 0.12);
      if (ringRef.current) {
        ringRef.current.style.left = ring.current.x + "px";
        ringRef.current.style.top = ring.current.y + "px";
      }
      raf.current = requestAnimationFrame(animate);
    };
    raf.current = requestAnimationFrame(animate);

    window.addEventListener("mousemove", onMove);
    window.addEventListener("mousedown", onDown);
    window.addEventListener("mouseup", onUp);
    document.documentElement.addEventListener("mouseleave", onLeave);
    document.documentElement.addEventListener("mouseenter", onEnter);
    return () => {
      cancelAnimationFrame(raf.current);
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mousedown", onDown);
      window.removeEventListener("mouseup", onUp);
      document.documentElement.removeEventListener("mouseleave", onLeave);
      document.documentElement.removeEventListener("mouseenter", onEnter);
    };
  }, []);

  const dotSize = clicked ? 6 : 8;
  const ringSize = onLink ? 48 : clicked ? 20 : 36;

  return (
    <>
      <style>{`
        @media (pointer: coarse) { .cur-dot, .cur-ring { display: none !important; } }
        body { cursor: none !important; }
        a, button { cursor: none !important; }
        .cur-dot {
          position: fixed; pointer-events: none; z-index: 9999;
          border-radius: 50%; background: #10b981;
          transform: translate(-50%, -50%);
          transition: width 0.15s, height 0.15s, opacity 0.3s;
          mix-blend-mode: difference;
        }
        .cur-ring {
          position: fixed; pointer-events: none; z-index: 9998;
          border-radius: 50%; border: 1.5px solid rgba(16,185,129,0.6);
          transform: translate(-50%, -50%);
          transition: width 0.3s cubic-bezier(0.16,1,0.3,1), height 0.3s cubic-bezier(0.16,1,0.3,1), opacity 0.3s, border-color 0.3s;
          backdrop-filter: blur(0px);
        }
      `}</style>
      <div
        ref={dotRef}
        className="cur-dot"
        style={{ width: dotSize, height: dotSize, opacity: visible ? 1 : 0 }}
      />
      <div
        ref={ringRef}
        className="cur-ring"
        style={{
          width: ringSize, height: ringSize,
          opacity: visible ? 1 : 0,
          borderColor: onLink ? "rgba(16,185,129,0.9)" : "rgba(16,185,129,0.5)",
          background: onLink ? "rgba(16,185,129,0.06)" : "transparent",
        }}
      />
    </>
  );
}
